import { Component, input, output, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { TooltipModule } from 'primeng/tooltip';
import { ButtonModule } from 'primeng/button';
import { AppDefinitionListItem } from '../../models/app-store.models';
import { AppRatingDisplayComponent } from '../app-rating-display/app-rating-display.component';
import { ImgFallbackDirective } from '../../../../shared/directives/img-fallback.directive';
import { isDefined } from '../../../../shared/utils';

@Component({
  selector: 'app-card',
  imports: [
    CommonModule,
    RouterModule,
    TooltipModule,
    ButtonModule,
    AppRatingDisplayComponent,
    ImgFallbackDirective,
  ],
  templateUrl: './app-card.component.html',
  styleUrls: ['./app-card.component.scss'],
})
export class AppCardComponent {
  readonly app = input.required<AppDefinitionListItem>();
  readonly isLoading = input<boolean>(false);
  readonly cardClick = output<void>();
  readonly installClick = output<void>();
  readonly uninstallClick = output<void>();

  readonly appDetailRoute = computed(() => ['/app-store', this.app().id]);
  readonly installationId = computed(() => this.app().installation?.id ?? null);
  readonly isAppInstalled = computed(() => isDefined(this.app().installation));
}
